import React, { useState, useEffect } from "react";
import axios from "axios";import data from "./data/modelPerformance.json";

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LabelList
} from "recharts";

function ModelAccuracy() {
  // --- Step 1: State for data ---
  const [data, setData] = useState([
    { name: "Linear Regression", accuracy: 0.65, rmse: 0.35 },
    { name: "Decision Tree", accuracy: 0.72, rmse: 0.28 },
    { name: "Random Forest", accuracy: 0.88, rmse: 0.12 },
    { name: "Gradient Boosting", accuracy: 0.91, rmse: 0.09 }
  ]);

  // --- Optional: Fetch from backend ---
  /*
  useEffect(() => {
    axios.get("/api/model-performance")
      .then(res => setData(res.data))
      .catch(err => console.error("Error fetching data:", err));
  }, []);
  */

  return (
    <div style={{ width: "90%", margin: "40px auto", textAlign: "center" }}>
      {/* TITLE */}
      <h2>MODEL PERFORMANCE COMPARISON: SALARY PREDICTION SYSTEM</h2>
      <p>Comparing ML Models across Key Metrics for Accuracy and Error</p>

      {/* GRID / TABLE */}
      <table style={{ width: "80%", margin: "20px auto", textAlign: "center", borderCollapse: "collapse" }}>
        <thead>
          <tr>
            <th style={{ borderBottom: "2px solid #ccc", padding: "10px" }}>Model</th>
            <th style={{ borderBottom: "2px solid #ccc", padding: "10px" }}>Accuracy</th>
            <th style={{ borderBottom: "2px solid #ccc", padding: "10px" }}>RMSE</th>
          </tr>
        </thead>
        <tbody>
          {data.map((model, index) => (
            <tr key={index}>
              <td style={{ padding: "10px" }}>{model.name}</td>
              <td style={{ padding: "10px" }}>{(model.accuracy * 100).toFixed(2)}%</td>
              <td style={{ padding: "10px" }}>{(model.rmse * 100).toFixed(2)}%</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* CHART: Always show for all models */}
      <div style={{ marginTop: "40px" }}>
        <ResponsiveContainer width="100%" height={400}>
          <BarChart data={data}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="name" />
            <YAxis domain={[0, 1]} />
            <Tooltip formatter={(value) => (value * 100).toFixed(2) + "%"} />
            <Legend />
            <Bar dataKey="accuracy" fill="#FFA500" name="Accuracy (R²)">
              <LabelList
                dataKey="accuracy"
                position="top"
                formatter={(value) => (value * 100).toFixed(2) + "%"}
              />
            </Bar>
            <Bar dataKey="rmse" fill="#2E75B6" name="RMSE">
              <LabelList
                dataKey="rmse"
                position="top"
                formatter={(value) => (value * 100).toFixed(2) + "%"}
              />
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* FOOTER NOTE */}
      <p style={{ marginTop: "20px", fontSize: "14px", color: "gray" }}>
        Note: RMSE is scaled to 0-1 for direct visual comparison with R² Accuracy.
      </p>
    </div>
  );
}

export default ModelAccuracy;
